import { useState } from 'react';
import type React from 'react';

import { cva, type VariantProps } from 'class-variance-authority';

import CloseIcon from '../icons/CloseIcon';
import { cn } from '../utils/cn';

const bannerVariants = cva(
  'flex items-center gap-3 rounded-lg border px-4 py-3 text-sm',
  {
    variants: {
      variant: {
        info: 'bg-brand-primary-50 border-brand-primary-200 text-brand-primary-800',
        success: 'bg-success-100 border-success-300 text-success-800',
        warning: 'bg-warning-100 border-warning-300 text-warning-800',
        danger: 'bg-danger-100 border-danger-300 text-danger-800',
      },
    },
    defaultVariants: {
      variant: 'info',
    },
  }
);

type BannerProps = React.ComponentProps<'div'> &
  VariantProps<typeof bannerVariants> & {
    /** When true, shows a close button that hides the banner on click. */
    dismissible?: boolean;
    /** Callback fired when the banner is dismissed. */
    onDismiss?: () => void;
  };

/**
 * A notification banner with semantic color variants.
 */
function Banner({
  className,
  variant,
  dismissible = false,
  onDismiss,
  children,
  ...props
}: BannerProps) {
  const [dismissed, setDismissed] = useState(false);

  if (dismissed) return null;

  return (
    <div
      data-slot="banner"
      role="status"
      className={cn(bannerVariants({ variant }), className)}
      {...props}
    >
      {children}
      {dismissible && (
        <button
          data-slot="banner-close"
          type="button"
          aria-label="Dismiss"
          className="ml-auto shrink-0 rounded p-0.5 opacity-70 hover:opacity-100 transition-opacity"
          onClick={() => {
            setDismissed(true);
            onDismiss?.();
          }}
        >
          <CloseIcon className="size-4" />
        </button>
      )}
    </div>
  );
}

export { Banner, bannerVariants };
